local function DoGasDamage(self, amount, doer, ...) local immunity = self.inst:GetCharacterBonus( "poisonimmunity" ) > 0x0 or self.inst:GetCharacterBonus( "sacreddefense" ) > 0x0 if immunity then return end if self.dycOldDoGasDamage then return self.dycOldDoGasDamage(self, amount, doer, ...) end end local function DoFireDamage(self, amount, doer, ...) local owner = self.inst local fScale = self.fire_damage_scale or 0x1 local fr = owner and owner.GetCharacterBonus and owner:GetCharacterBonus( "fireresistance" ) or 0x0 fr = owner and owner.GetCharacterBonus and owner:GetCharacterBonus( "sacreddefense" ) > 0x0 and 0x3e7 or fr self.fire_damage_scale = math.max(0x0, math.min(fScale - fr, 0x1)) local retVal = self.dycOldDoFireDamage(self, amount, doer, ...) self.fire_damage_scale = fScale return retVal end local function GetBonusHealth(self) local encBonus = 0x0 local encPercentageBonus = 0x0 local owner = self.inst if owner and owner.GetCharacterBonus then encBonus = owner:GetCharacterBonus( "maxhealth" ) encPercentageBonus = owner:GetCharacterBonus( "maxhealth_percent" ) end return(self.maxhealth + encBonus) * (0x1 + encPercentageBonus) - self.maxhealth end local function GetMax(self) return self.maxhealth + GetBonusHealth(self) end local function GetMaxHealth(self, ...) return self.dycOldGetMaxHealth(self, ...) + GetBonusHealth(self) end local function GetPenaltyPercent(self, ...) return(self.penalty * TUNING.EFFIGY_HEALTH_PENALTY) / GetMax(self) end local function GetPercent(self, ...) return self.currenthealth / GetMax(self) end local function SetPercent(self, percent, cause, ...) self:SetVal(GetMax(self) * percent, cause) self:DoDelta(0x0) end local function OnLoad(self, data, ...) if self.inst and data and data.health then self.inst:DoTaskInTime(FRAMES * 0x3, function() if self.inst:IsValid() then self:SetVal(data.health, "file_load" ) self:DoDelta(0x0) end end) end return self.dycOldOnLoad(self, data, ...) end local function DYCHealth(self) self.dycOldDoGasDamage = self.DoGasDamage self.DoGasDamage = DoGasDamage self.dycOldDoFireDamage = self.DoFireDamage self.DoFireDamage = DoFireDamage self.SetPercent = SetPercent self.GetPercent = GetPercent self.dycOldGetMaxHealth = self.GetMaxHealth self.GetMaxHealth = GetMaxHealth self.GetPenaltyPercent = GetPenaltyPercent self.dycOldOnLoad = self.OnLoad self.OnLoad = OnLoad self.GetMax = GetMax end return DYCHealth 